import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const [requests, setRequests] = useState([]);

  const user = JSON.parse(localStorage.getItem("user"));

  const fetchRequests = async () => {

    const res = await axios.get(
      `http://localhost:5000/api/request/labour/${user._id}`
    );

    setRequests(res.data);
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  // =========================
  // LABOUR RESPONSE
  // =========================
  const respond = async (id) => {

    const price = prompt("Enter price");
    const action = prompt("Accepted or Rejected");

    await axios.put(
      `http://localhost:5000/api/request/labour-response/${id}`,
      { price, action }
    );

    fetchRequests();
  };

  return (

    <div>
      <Navbar />

      <div style={{ padding: 20 }}>

        <h2>Labour Dashboard</h2>

        {requests.map(r => (

          <div key={r._id} style={{ border: "1px solid gray", margin: 10, padding: 10 }}>

            <p>Customer: {r.customerName}</p>
            <p>Work: {r.workType}</p>
            <p>Date: {r.date}</p>
            <p>Time: {r.timings?.join(", ")}</p>

            <p>Status: {r.status}</p>

            <p>Customer Decision: {r.customerDecision}</p>

            <button onClick={() => respond(r._id)}>
              Respond (Price + Accept/Reject)
            </button>

          </div>
        ))}

      </div>
    </div>
  );
}
